    UFUNCTION(BlueprintCallable, Category = "Skill|Priority")
    void OnSkillUsed();

    // жҜҸиҪ®еӣһеӨҚдјҳе…Ҳзә§пјҲеңЁ OnTurnStart дёӯи°ғз”Ёпјү
    UFUNCTION(BlueprintCallable, Category = "Skill|Priority")
    void RecoverPriority();

