    UFUNCTION(BlueprintNativeEvent, BlueprintPure, Category = "Skill|Priority")
    float EvaluateConditionBonus() const;

    // иҺ·еҸ–жң¬иҪ®жңүж•Ҳдјҳе…Ҳзә§пјҲеҪ“еүҚеҖј + жқЎд»¶еҠ жҲҗпјү
