445вҶ’void ULFPSkillSelectionWidget::SortSkills(ESkillSortMethod SortMethod)
446вҶ’{
447вҶ’    if (!OwnerUnit) return;
448вҶ’
449вҶ’    // иҺ·еҸ–еҪ“еүҚжҳҫзӨәзҡ„жҠҖиғҪ
450вҶ’    TArray<ULFPSkillBase*> CurrentSkills;
451вҶ’    for (ULFPSkillButtonWidget* Button : SkillButtons)
452вҶ’    {
453вҶ’        if (Button && Button->GetSkill())
454вҶ’        {
455вҶ’            CurrentSkills.Add(Button->GetSkill());
456вҶ’        }
457вҶ’    }
458вҶ’
459вҶ’    // ж №жҚ®жҺ’еәҸж–№жі•жҺ’еәҸ
460вҶ’    switch (SortMethod)
461вҶ’    {
462вҶ’    case ESkillSortMethod::ByName:
463вҶ’        CurrentSkills.Sort([](const ULFPSkillBase& A, const ULFPSkillBase& B) {
464вҶ’            return A.SkillName.ToString() < B.SkillName.ToString();
465вҶ’            });
466вҶ’        break;
467вҶ’
468вҶ’    case ESkillSortMethod::ByCooldown:
469вҶ’        CurrentSkills.Sort([](const ULFPSkillBase& A, const ULFPSkillBase& B) {
470вҶ’            return A.CurrentCooldown < B.CurrentCooldown;
471вҶ’            });
472вҶ’        break;
473вҶ’
474вҶ’    case ESkillSortMethod::ByCost:
475вҶ’        CurrentSkills.Sort([](const ULFPSkillBase& A, const ULFPSkillBase& B) {
476вҶ’            return A.ActionPointCost < B.ActionPointCost;
477вҶ’            });
478вҶ’        break;
479вҶ’
480вҶ’    case ESkillSortMethod::ByType:
481вҶ’        // йңҖиҰҒж·»еҠ жҠҖиғҪзұ»еһӢеұһжҖ§пјҢеҰӮSkillTypeеӯ—ж®ө
482вҶ’        // CurrentSkills.Sort([](const ULFPSkillBase& A, const ULFPSkillBase& B) {
483вҶ’        //     return A.SkillType < B.SkillType;
484вҶ’        // });
485вҶ’        break;
486вҶ’    }
487вҶ’
488вҶ’    // йҮҚж–°жҺ’еҲ—жүҖжңүжҠҖиғҪжҢүй’®
489вҶ’    if (SkillGrid)
490вҶ’    {
491вҶ’        SkillGrid->ClearChildren();
492вҶ’
493вҶ’        int32 Row = 0;
494вҶ’        int32 Column = 0;
495вҶ’
496вҶ’        for (ULFPSkillBase* Skill : CurrentSkills)
497вҶ’        {
498вҶ’            // жүҫеҲ°еҜ№еә”зҡ„жҢүй’®
499вҶ’            for (ULFPSkillButtonWidget* Button : SkillButtons)
500вҶ’            {
501вҶ’                if (Button && Button->GetSkill() == Skill)
502вҶ’                {
503вҶ’                    SkillGrid->AddChildToUniformGrid(Button, Row, Column);
504вҶ’
505вҶ’                    Column++;
506вҶ’                    if (Column >= MaxColumns)
507вҶ’                    {
508вҶ’                        Column = 0;
509вҶ’                        Row++;
510вҶ’                    }
511вҶ’
512вҶ’                    break;
513вҶ’                }
514вҶ’            }
515вҶ’        }
516вҶ’    }
517вҶ’}
