    if (!Skill) return;

    // жӣҙж–°жҠҖиғҪиҜҰжғ…
    UpdateSkillDetails(Skill);

    // жҳҫзӨәиҜҰжғ…йқўжқҝ
    if (SkillDetailsPanel)
    {
        SkillDetailsPanel->SetVisibility(ESlateVisibility::Visible);
    }

    //// ж’ӯж”ҫжӮ¬еҒңйҹіж•Ҳ
